Ensure all interactive elements are keyboard accessible.

```gjs
import { on } from '@ember/modifier';

<template>
  <div
    role="button"
    tabindex="0"
    {{on 'click' this.handleAction}}
    {{on 'keydown' this.handleKeydown}}
  >
    {{@label}}
  </div>
</template>

export class ClickableDiv extends Component {
  handleKeydown = (event) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      this.handleAction();
    }
  };

  handleAction = () => {
    this.args.onClick?.();
  };
}
```

Better yet, use semantic HTML: `<button>` instead of `<div role="button">`.

Cache expensive API responses in services to reduce redundant network calls.

```javascript
import Service from '@ember/service';
import { tracked } from '@glimmer/tracking';

export class ApiCache extends Service {
  @tracked cache = new Map();

  async fetch(url, options = {}) {
    const cacheKey = `${url}:${JSON.stringify(options)}`;
    const maxAge = options.maxAge ?? 300000; // 5 minutes default

    const cached = this.cache.get(cacheKey);
    if (cached && Date.now() - cached.timestamp < maxAge) {
      return cached.data;
    }

    const response = await fetch(url, options);
    const data = await response.json();

    this.cache.set(cacheKey, { data, timestamp: Date.now() });
    return data;
  }

  invalidate(urlPattern) {
    for (const key of this.cache.keys()) {
      if (key.includes(urlPattern)) {
        this.cache.delete(key);
      }
    }
  }
}
```

Use services for state that needs to be shared across components or routes.

```javascript
import Service from '@ember/service';
import { tracked } from '@glimmer/tracking';

export class SessionService extends Service {
  @tracked currentUser = null;
  @tracked isAuthenticated = false;

  async login(credentials) {
    const response = await fetch('/api/login', {
      method: 'POST',
      body: JSON.stringify(credentials)
    });
    this.currentUser = await response.json();
    this.isAuthenticated = true;
  }

  logout() {
    this.currentUser = null;
    this.isAuthenticated = false;
  }
}
```

Inject with `@service session` in components that need access.

Move complex logic out of templates into component getters or helpers.

âťŚ Heavy template computation:
```handlebars
{{#each (filter this.items (fn this.matchesSearch this.searchTerm)) as |item|}}
  <Item @data={{item}} />
{{/each}}
```

âś… Use cached getter:
```javascript
import { cached } from '@glimmer/tracking';

@cached
get filteredItems() {
  return this.items.filter(item => 
    item.name.toLowerCase().includes(this.searchTerm.toLowerCase())
  );
}
```

```handlebars
{{#each this.filteredItems as |item|}}
  <Item @data={{item}} />
{{/each}}
```

Leverage Ember's built-in helpers instead of creating custom ones.

Built-in helpers:
- `{{if}}`, `{{unless}}` - Conditionals
- `{{eq}}`, `{{not-eq}}`, `{{and}}`, `{{or}}`, `{{not}}` - Comparisons
- `{{array}}`, `{{hash}}` - Data structures
- `{{fn}}` - Partial application
- `{{concat}}` - String concatenation
- `{{get}}` - Dynamic property access

```handlebars
{{! Use built-in eq instead of custom isEqual helper }}
{{#if (eq @status "active")}}
  <ActiveBadge />
{{/if}}

{{! Use and/or for boolean logic }}
{{#if (and @isLoggedIn @hasPermission)}}
  <AdminPanel />
{{/if}}
```

In GJS/GTS files, import and use helpers directly in the template scope.

```gjs
import { eq, and, or } from '@ember/helper';
import { on } from '@ember/modifier';
import { hash } from '@ember/helper';

<template>
  {{#if (and @isVisible (eq @mode "edit"))}}
    <EditForm @data={{hash name=@name email=@email}} />
  {{/if}}

  <button {{on 'click' @onSave}}>Save</button>
</template>
```

This makes dependencies explicit and enables better tree-shaking.

Prefer template-only components for simple presentational components.

```gts
import type { TOC } from '@ember/component/template-only';

interface UserCardSignature {
  Args: {
    user: { name: string; email: string };
  };
}

const UserCard: TOC<UserCardSignature> = <template>
  <div class="user-card">
    <h3>{{@user.name}}</h3>
    <p>{{@user.email}}</p>
  </div>
</template>;

export { UserCard };
```

Template-only components are lighter, more performant, and easier to understand.

Use ember-resources for managing async data with proper lifecycle handling.

```javascript
import { use } from 'ember-resources';
import { RemoteData } from 'ember-resources/remote-data';

export class UserProfile extends Component {
  userData = use(this, RemoteData(() => `/api/users/${this.args.userId}`));

  <template>
    {{#if this.userData.isLoading}}
      <Spinner />
    {{else if this.userData.isError}}
      <Error @message={{this.userData.error.message}} />
    {{else}}
      <Profile @user={{this.userData.value}} />
    {{/if}}
  </template>
}
```

Resources automatically clean up when the component is destroyed.

Use ember-concurrency for complex async operations with cancellation and state management.

```javascript
import { task, timeout } from 'ember-concurrency';

export class SearchComponent extends Component {
  @task({ restartable: true })
  *search(query) {
    yield timeout(300); // Debounce

    const response = yield fetch(`/api/search?q=${query}`);
    return yield response.json();
  }

  <template>
    <input {{on 'input' (fn this.search.perform event.target.value)}} />

    {{#if this.search.isRunning}}
      <Spinner />
    {{else if this.search.lastSuccessful}}
      <Results @items={{this.search.lastSuccessful.value}} />
    {{/if}}
  </template>
}
```

Tasks handle cancellation, loading states, and error handling automatically.

Use the right render pattern for your test scenario.

```javascript
import { module, test } from 'qunit';
import { setupRenderingTest } from 'ember-qunit';
import { render, click, fillIn } from '@ember/test-helpers';
import { hbs } from 'ember-cli-htmlbars';

module('Integration | Component | login-form', function(hooks) {
  setupRenderingTest(hooks);

  test('submits form with credentials', async function(assert) {
    let submittedData = null;
    this.set('onSubmit', (data) => submittedData = data);

    await render(hbs`
      <LoginForm @onSubmit={{this.onSubmit}} />
    `);

    await fillIn('[data-test-email]', 'user@example.com');
    await fillIn('[data-test-password]', 'secret');
    await click('[data-test-submit]');

    assert.deepEqual(submittedData, {
      email: 'user@example.com',
      password: 'secret'
    });
  });
});
```

Create composed helpers for complex template logic.

```javascript
// app/helpers/format-currency.js
import { helper } from '@ember/component/helper';

export function formatCurrency([amount, currency = 'USD']) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency
  }).format(amount);
}

export default helper(formatCurrency);
```

Usage in template:
```handlebars
<span>{{format-currency @price "EUR"}}</span>
```

For more complex cases, use class-based helpers with tracking.

Build reactive chains by having getters depend on other tracked properties or getters.

```javascript
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { cached } from '@glimmer/tracking';

export class DataTable extends Component {
  @tracked sortField = 'name';
  @tracked sortDirection = 'asc';
  @tracked filterText = '';

  @cached
  get filteredItems() {
    return this.args.items.filter(item =>
      item.name.toLowerCase().includes(this.filterText.toLowerCase())
    );
  }

  @cached
  get sortedItems() {
    return [...this.filteredItems].sort((a, b) => {
      const cmp = a[this.sortField].localeCompare(b[this.sortField]);
      return this.sortDirection === 'asc' ? cmp : -cmp;
    });
  }
}
```

Each getter only recalculates when its dependencies change.

Use controlled components for form inputs with explicit state management.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { on } from '@ember/modifier';

export class ContactForm extends Component {
  @tracked name = '';
  @tracked email = '';

  updateName = (event) => {
    this.name = event.target.value;
  };

  updateEmail = (event) => {
    this.email = event.target.value;
  };

  submit = (event) => {
    event.preventDefault();
    this.args.onSubmit?.({ name: this.name, email: this.email });
  };

  <template>
    <form {{on 'submit' this.submit}}>
      <input value={{this.name}} {{on 'input' this.updateName}} />
      <input value={{this.email}} {{on 'input' this.updateEmail}} />
      <button type="submit">Submit</button>
    </form>
  </template>
}
```

Implement robust data fetching with retry logic and error handling.

```javascript
import Service from '@ember/service';

export class ApiService extends Service {
  async request(url, options = {}) {
    const maxRetries = options.retries ?? 3;
    const retryDelay = options.retryDelay ?? 1000;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        const response = await fetch(url, {
          ...options,
          headers: {
            'Content-Type': 'application/json',
            ...options.headers
          }
        });

        if (!response.ok) {
          throw new Error(`HTTP ${response.status}`);
        }

        return await response.json();
      } catch (error) {
        if (attempt === maxRetries) throw error;
        await new Promise(r => setTimeout(r, retryDelay * attempt));
      }
    }
  }
}
```
